import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AddEmployee.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    email: "",
    dob: "",
    age: "",
    phone: "",
    gender: "",
    maritalStatus: "",

    designation: "",
    salary: "",
    department: "",
    role: "Employee",
    skills: "",
    otherSkill: "",

    bankHolderName: "",
    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: "",
  });

  // 🔴 Error State
  const [errors, setErrors] = useState({
    email: "",
    phone: "",
    ifsc: ""
  });

  // ---------- LOAD EXISTING DATA ----------
  useEffect(() => {
    if (!id) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find((emp) => emp.id === id);

    if (found) setEmployee(found);
  }, [id]);


  // ---------- VALIDATION FUNCTIONS ----------
  const validateEmail = (email) => {
    const pattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return pattern.test(email);
  };

  const validatePhone = (phone) => {
    const pattern = /^[0-9]{10}$/;
    return pattern.test(phone);
  };

  const validateIFSC = (code) => {
    const pattern = /^[A-Z]{4}0[A-Z0-9]{6}$/;
    return pattern.test(code.toUpperCase());
  };


  // ---------- HANDLE INPUT ----------
  const handleChange = (e) => {
    const { name, value } = e.target;

    // Auto Age
    if (name === "dob") {
      const birthYear = new Date(value).getFullYear();
      const currentYear = new Date().getFullYear();
      const calculatedAge = currentYear - birthYear;

      setEmployee({ ...employee, dob: value, age: calculatedAge });
      return;
    }

    setEmployee({ ...employee, [name]: value });

    // Email Validation
    if (name === "email") {
      setErrors({
        ...errors,
        email: validateEmail(value) ? "" : "Invalid Email Format"
      });
    }

    // Phone Validation
    if (name === "phone") {
      setErrors({
        ...errors,
        phone: validatePhone(value) ? "" : "Phone must be 10 Digits"
      });
    }

    // IFSC Validation
    if (name === "ifsc") {
      setErrors({
        ...errors,
        ifsc: validateIFSC(value) ? "" : "Invalid IFSC Format (Ex: SBIN0001234)"
      });
    }
  };


  // ---------- SAVE / UPDATE ----------
  const handleSubmit = (e) => {
    e.preventDefault();

    // Final blocking validation
    if (!validateEmail(employee.email)) {
      alert("Please enter valid Email");
      return;
    }

    if (!validatePhone(employee.phone)) {
      alert("Phone must be 10 digits");
      return;
    }

    if (!validateIFSC(employee.ifsc)) {
      alert("Invalid IFSC Code");
      return;
    }

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      employees = employees.map((emp) =>
        emp.id === id ? { ...employee } : emp
      );
      alert("Employee Updated Successfully!");
    } else {
      const newEmployee = {
        ...employee,
        id: Date.now().toString(),
      };
      employees.push(newEmployee);
      alert("Employee Added Successfully!");
    }

    localStorage.setItem("employees", JSON.stringify(employees));
    navigate("/dashboard/employee-details");
  };


  return (
    <div className="add-employee-page">
      <h2>{id ? "Edit Employee" : "Add Employee"}</h2>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* ---------------- PERSONAL DETAILS ---------------- */}
        <h3>Personal Details</h3>

        <div className="employee-grid">

          <input
            name="firstName"
            placeholder="First Name"
            value={employee.firstName}
            onChange={handleChange}
          />

          <input
            name="lastName"
            placeholder="Last Name"
            value={employee.lastName}
            onChange={handleChange}
          />

          <input
            name="empId"
            placeholder="Employee ID"
            value={employee.empId}
            onChange={handleChange}
          />

          <input
            name="email"
            placeholder="Email"
            value={employee.email}
            onChange={handleChange}
          />
          {errors.email && <span className="error-text">{errors.email}</span>}

          <input
            type="date"
            name="dob"
            value={employee.dob}
            onChange={handleChange}
          />

          <input
            name="age"
            placeholder="Age"
            value={employee.age}
            disabled
          />

          <input
            name="phone"
            placeholder="Phone Number"
            value={employee.phone}
            onChange={handleChange}
          />
          {errors.phone && <span className="error-text">{errors.phone}</span>}

          <select
            name="gender"
            value={employee.gender}
            onChange={handleChange}
          >
            <option value="">Select Gender</option>
            <option>Male</option>
            <option>Female</option>
            
          </select>

          <select
            name="maritalStatus"
            value={employee.maritalStatus}
            onChange={handleChange}
          >
            <option value="">Select Marital Status</option>
            <option>Single</option>
            <option>Married</option>
            
        
          </select>

        </div>


        {/* ---------------- JOB DETAILS ---------------- */}
        <h3>Job Details</h3>

        <div className="employee-grid">

          <input
            name="designation"
            placeholder="Designation"
            value={employee.designation}
            onChange={handleChange}
          />

          <input
            name="salary"
            placeholder="Salary"
            value={employee.salary}
            onChange={handleChange}
          />

          <select
            name="department"
            value={employee.department}
            onChange={handleChange}
          >
            <option value="">Select Department</option>
            <option>Frontend</option>
            <option>Backend</option>
            <option>Web Developer</option>
            <option>Quality Check (QC)</option>
            <option>Database</option>
            <option>IT</option>
            <option>Digital Marketing</option>
            <option>HR</option>
            <option>Sales</option>
            <option>USIT Recruiters</option>
            <option>Business Developer</option>
          </select>

          <select
            name="skills"
            value={employee.skills}
            onChange={handleChange}
          >
            <option value="">Select Skill</option>
            <option>Java</option>
            <option>Advanced Java</option>
            <option>Python</option>
            <option>NodeJS</option>
            <option>React</option>
            <option>Angular</option>
            <option>MongoDB</option>
            <option>Other</option>
          </select>

          {employee.skills === "Other" && (
            <input
              name="otherSkill"
              placeholder="Enter Skill"
              value={employee.otherSkill}
              onChange={handleChange}
            />
          )}

          <select
            name="role"
            value={employee.role}
            onChange={handleChange}
          >
            <option>Employee</option>
            <option>Admin</option>
          </select>

        </div>


        {/* ---------------- BANK DETAILS ---------------- */}
        <h3>Bank Details</h3>

        <div className="employee-grid">

          <input
            name="bankHolderName"
            placeholder="Account Holder Name"
            value={employee.bankHolderName}
            onChange={handleChange}
          />

          <input
            name="bankName"
            placeholder="Bank Name"
            value={employee.bankName}
            onChange={handleChange}
          />

          <input
            name="accountNumber"
            placeholder="Account Number"
            value={employee.accountNumber}
            onChange={handleChange}
          />

          <input
            name="ifsc"
            placeholder="IFSC Code"
            value={employee.ifsc}
            onChange={handleChange}
          />
          {errors.ifsc && <span className="error-text">{errors.ifsc}</span>}

        </div>


        {/* ---------------- EDUCATION ---------------- */}
        <h3>Educational Details</h3>

        <div className="employee-grid">

          <input
            name="qualification"
            placeholder="Highest Qualification"
            value={employee.qualification}
            onChange={handleChange}
          />

          <input
            name="university"
            placeholder="University"
            value={employee.university}
            onChange={handleChange}
          />

          <input
            name="passingYear"
            placeholder="Passing Year"
            value={employee.passingYear}
            onChange={handleChange}
          />

        </div>

        <button type="submit" className="save-btn">
          {id ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
